            "fallback_routing_rules": {
              "operation": "condition_map",
              "_note": "Phase 3: determines where to route when resolve_entity (workflow step 1) cannot pin down a specific named service. Archaeology finding: this exact 3-tier fallback chain (group match -> synthesize Other tile via resolve_dynamic_service; category match only -> generic wizard; no match at all -> intent_mappings.default_fallback) already exists correctly in the legacy sqAnalyze/prefillSmartQuoteFromOtherTile code -- this node makes it an explicit, auditable rule set. Does NOT change behavior; documents and formalizes what the verified-correct legacy code already does.",
              "rules": [
                {
                  "if": {
                    "has_category": true,
                    "has_group": true,
                    "match_confidence_at_least": 50
                  },
                  "then": {
                    "route_to": "dynamic_services",
                    "via": "resolve_dynamic_service(category, stype, groupId)",
                    "render_as": "synthetic_other_tile"
                  },
                  "_note": "category + group both resolved with reasonable confidence -- the most common real fallback case (e.g. 'mount a projector screen' correctly landing in wall_mounting_tv_flatscreen)."
                },
                {
                  "if": {
                    "has_category": true,
                    "has_group": false
                  },
                  "then": {
                    "route_to": "generic_wizard",
                    "_legacy_fn": "sqPrepareFlow(skipStep2=false)"
                  },
                  "_note": "Category known but no specific group match -- ask the customer directly rather than guess a group, exactly the discipline that fixed the original 'groups[0] -> Appliances' misrouting bug found earlier this session."
                },
                {
                  "if": {
                    "has_category": false
                  },
                  "then": {
                    "route_to": "intent_mappings.default_fallback"
                  },
