          "invariants": [
            {
              "id": "route_must_be_real_object",
              "rule": "A ResolvedRoute must be a real, non-null object",
              "check": {
                "type": "exists",
                "field": "$root"
              },
              "_note": "The most basic possible guarantee -- if the Orchestrator somehow produces undefined/null, nothing downstream should ever see it."
            },
            {
              "id": "uitemplate_must_be_known",
              "rule": "uiTemplate must be one of the engine's real, defined templates",
              "check": {
                "type": "enum",
                "field": "uiTemplate",
                "allowed": [
                  "self_quote",
                  "curated_card",
                  "chip_grid",
                  "legacy_flow"
                ]
              },
              "_note": "Catches a broken or stale ui_template_matrix rule producing a typo'd or removed template name -- exactly the failure mode this was first built to catch (a deliberately broken matrix.fallback during Phase 4 development)."
            },
            {
              "id": "legacy_flow_requires_entity",
              "rule": "If uiTemplate is legacy_flow, a real entity must be resolved",
              "check": {
                "type": "conditional_exists",
                "if_field": "uiTemplate",
                "if_value": "legacy_flow",
                "then_field": "entity"
              },
              "_note": "legacy_flow specifically hands off to showIntakeQuestions, which requires a real service object -- a furniture-selection or adhoc bypass with no entity has nothing for the legacy renderer to work with."
            },
            {
              "id": "question_templates_require_real_entity",
              "rule": "self_quote and curated_card require entityType to not be 'fallback'",
              "check": {
                "type": "conditional_not_equal",
                "if_field": "uiTemplate",
                "if_values": [
                  "self_quote",
                  "curated_card"
                ],
                "then_field": "entityType",
                "forbidden_value": "fallback"
              },
              "_note": "A question-asking template needs a real, resolved entity to ask questions ABOUT -- entityType:fallback means resolve_entity (workflow step 1) never found one."
            },
            {
              "id": "quote_never_negative",
              "rule": "quote.laborEstimate, if present, must be >= 0",
              "check": {
                "type": "non_negative",
                "field": "quote.laborEstimate"
              },
              "_note": "A real quote can never bill a negative amount -- catches a sign error or a pricing formula gone wrong upstream."
            },
            {
              "id": "materials_range_not_inverted",
              "rule": "materialsEstimate.min must be <= materialsEstimate.max",
              "check": {
                "type": "lte",
                "field_a": "materialsEstimate.min",
                "field_b": "materialsEstimate.max"
              },
              "_note": "An inverted range (min > max) is never meaningful and would display nonsensically to a customer."
            },
            {
              "id": "trace_required",
              "rule": "trace must be a real, non-empty array",
              "check": {
                "type": "non_empty_array",
                "field": "trace"
              },
              "_note": "Phase 7 observability (and the Historian replay mechanism) depend on every real route carrying its own execution history -- a route with no trace can never be debugged or replayed."
            }
          ],
